import { NextRequest, NextResponse } from "next/server";
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth/options";
import { WORKFLOW_API_BASE_URL, WORKFLOW_API_KEY, workflowApiUrl } from "@/lib/config";

export interface WorkflowJob {
  id: string;
  name: string;
  status: string;
  state_index: number;
  assignee_email: string | null;
  system_department: string | null;
  external_job_id: string | null;
  is_revision: boolean;
  metadata: Record<string, unknown>;
  created_at: string;
  updated_at: string;
}

export interface Job {
  id: string;
  name: string;
  status: string;
  external_job_id: string | null;
  system_department: string | null;
  assignee_email: string | null;
  is_revision: boolean;
  created_at: string;
  updated_at: string;
}

export interface JobsResponse {
  jobs: Job[];
  count: number;
}

export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    if (!session?.accessToken) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    if (!WORKFLOW_API_BASE_URL) {
      return NextResponse.json({ error: "Workflow API base URL not configured" }, { status: 500 });
    }

    if (!WORKFLOW_API_KEY) {
      return NextResponse.json({ error: "Workflow API key not configured" }, { status: 500 });
    }

    const userEmail = session.user?.email;
    if (!userEmail) {
      return NextResponse.json({ error: "User email not found in session" }, { status: 400 });
    }

    const { searchParams } = new URL(req.url);
    const systemDepartment = searchParams.get("system_department");
    const status = searchParams.get("status");
    const limit = searchParams.get("limit") || "100";
    const offset = searchParams.get("offset") || "0";

    // Build query params for workflow API
    const params = new URLSearchParams();
    params.append("assignee_email", userEmail);
    params.append("limit", limit);
    params.append("offset", offset);
    if (systemDepartment) params.append("system_department", systemDepartment);
    if (status) params.append("status", status);

    const upstreamUrl = workflowApiUrl(`/api/jobs?${params.toString()}`);

    const upstreamRes = await fetch(upstreamUrl, {
      headers: {
        "x-api-key": WORKFLOW_API_KEY,
        "Content-Type": "application/json",
      },
      cache: "no-store",
    });

    if (!upstreamRes.ok) {
      const text = await upstreamRes.text();
      return NextResponse.json(
        { error: "Upstream error", status: upstreamRes.status, details: text },
        { status: upstreamRes.status },
      );
    }

    const upstreamData = (await upstreamRes.json()) as
      | WorkflowJob[]
      | { jobs: WorkflowJob[] }
      | { data: WorkflowJob[] };

    // Normalize response to expected format
    let workflowJobs: WorkflowJob[] = [];
    if (Array.isArray(upstreamData)) {
      workflowJobs = upstreamData;
    } else if ("jobs" in upstreamData) {
      workflowJobs = upstreamData.jobs;
    } else if ("data" in upstreamData) {
      workflowJobs = upstreamData.data;
    }

    const jobs: Job[] = workflowJobs.map((job) => ({
      id: job.id,
      name: job.name,
      status: job.status,
      external_job_id: job.external_job_id,
      system_department: job.system_department,
      assignee_email: job.assignee_email,
      is_revision: job.is_revision,
      created_at: job.created_at,
      updated_at: job.updated_at,
    }));

    return NextResponse.json({ jobs, count: jobs.length }, { status: 200 });
  } catch (e) {
    console.error("/api/jobs error", e);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

// Central configuration helpers

// Normalize and export the external API base URL (env value includes /api/v1 already)
export const API_BASE_URL = (() => {
  const raw = process.env.NEXT_PUBLIC_API_BASE_URL || "";
  // Remove any trailing slash to avoid double slashes when concatenating paths
  return raw.replace(/\/$/, "");
})();

export const PRODUCT_API_BASE_URL = (() => {
  const raw = process.env.NEXT_PUBLIC_PRODUCT_API_BASE_URL || "";
  return raw.replace(/\/$/, "");
})();

export const ORDER_STATUS_API_BASE_URL = (() => {
  const raw = process.env.NEXT_PUBLIC_PRODUCT_API_BASE_URL || "";
  return raw.replace(/\/$/, "");
})();

export const ORDER_JOB_API_BASE_URL = (() => {
  const raw = process.env.NEXT_PUBLIC_ORDER_JOB_API_BASE_URL || "";
  return raw.replace(/\/$/, "");
})();

// Workflow Engine API configuration
export const WORKFLOW_API_BASE_URL = (() => {
  const raw = process.env.NEXT_PUBLIC_WORKFLOW_API_BASE_URL || "";
  return raw.replace(/\/$/, "");
})();

export const WORKFLOW_API_KEY = process.env.WORKFLOW_API_KEY || "";

// Helper to build full upstream URL paths safely
export function apiUrl(path: string) {
  const cleaned = path.startsWith("/") ? path : `/${path}`;
  return `${API_BASE_URL}${cleaned}`;
}

export function productApiUrl(path: string) {
  const cleaned = path.startsWith("/") ? path : `/${path}`;
  const base = PRODUCT_API_BASE_URL;
  return `${base}${cleaned}`;
}

export function orderStatusApiUrl(path: string) {
  const cleaned = path.startsWith("/") ? path : `/${path}`;
  const base = ORDER_STATUS_API_BASE_URL;
  return `${base}${cleaned}`;
}

export function orderJobApiUrl(path: string) {
  const cleaned = path.startsWith("/") ? path : `/${path}`;
  const base = ORDER_JOB_API_BASE_URL;
  return `${base}${cleaned}`;
}

export function workflowApiUrl(path: string) {
  const cleaned = path.startsWith("/") ? path : `/${path}`;
  const base = WORKFLOW_API_BASE_URL;
  return `${base}${cleaned}`;
}

